mapper.select:
SELECT DISTINCT
b.CODE,
a.expectedretrievaldate,
b.accentity
FROM
cmp_paymargin a
LEFT JOIN cmp_marginworkbench b ON a.marginvirtualaccount = b.id
WHERE
a.expectedretrievaldate between #{currentDate} and #{warnDate}
AND b.marginbalance > 0
AND a.tenant_id = #{tenantid}
AND a.ytenant_id = #{ytenantid}
AND b.tenant_id = #{tenantid}
AND b.ytenant_id = #{ytenantid}

    AND b.accentity IN

        #{item}
